33	// this function receives 2 pointers (indicated by *) so it can set their values
34	void getColors(uint8_t value, uint8_t scheme, uint8_t *foreground, uint8_t *background)
35	// scheme must be a valid index into the table of 4 schemes
36	__CPROVER_requires(scheme < 4)
37	// both output pointers must point to writable bytes
38	__CPROVER_requires(__CPROVER_w_ok(foreground, sizeof(uint8_t)))
39	__CPROVER_requires(__CPROVER_w_ok(background, sizeof(uint8_t)))
40	__CPROVER_assigns(*foreground, *background)
41	// the exact bytes written: odd table index for foreground, even index for background
42	__CPROVER_ensures(*foreground == COLOR_SCHEMES_TABLE[scheme][(1 + value * 2) % 32])
43	__CPROVER_ensures(*background == COLOR_SCHEMES_TABLE[scheme][(0 + value * 2) % 32])
44	{
45		uint8_t original[] = {8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0};
46		uint8_t blackwhite[] = {232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0};
47		uint8_t bluered[] = {235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255};
48		uint8_t whiteblack[] = {255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255};
49		uint8_t *schemes[] = {original, blackwhite, bluered, whiteblack};
50		// modify the 'pointed to' variables (using a * on the left hand of the assignment)
51		*foreground = *(schemes[scheme] + (1 + value * 2) % sizeof(original));
52		*background = *(schemes[scheme] + (0 + value * 2) % sizeof(original));
53		// alternatively we could have returned a struct with two variables
54	}
55	
56	// Powers of ten as 64-bit constants, indexed 0..10. Used by the getDigitCount
57	// contract to pin down the returned digit count without overflow (10^10 does
58	// not fit in uint32_t).
59	#define DC_POW10(k) (((const uint64_t[]){ \
60		1ULL, 10ULL, 100ULL, 1000ULL, 10000ULL, 100000ULL, \
61		1000000ULL, 10000000ULL, 100000000ULL, 1000000000ULL, 10000000000ULL})[(k)])
62	
63	uint8_t getDigitCount(uint32_t number)
64	// the count of decimal digits of a uint32_t is between 1 (for 0..9) and 10
65	__CPROVER_ensures(__CPROVER_return_value >= 1 && __CPROVER_return_value <= 10)
66	// the result d is the unique value with number < 10^d ...
67	__CPROVER_ensures((uint64_t)number < DC_POW10((int)__CPROVER_return_value))
68	// ... and number >= 10^(d-1), except 0 (which has no nonzero leading digit)
69	__CPROVER_ensures(__CPROVER_return_value == 1 || (uint64_t)number >= DC_POW10((int)__CPROVER_return_value - 1))
70	{
71		uint8_t count = 0;
72		do
73		{
74			number /= 10;
75			count += 1;
76		} while (number);
77		return count;
78	}
