80	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
81	// clang-format off
82	// the board must be a readable 4x4 block of bytes
83	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
84	// scheme is forwarded to getColors, whose contract requires a valid index
85	__CPROVER_requires(scheme < 4)
86	// each cell is a power-of-two exponent; drawBoard computes 1 << board[x][y],
87	// which is undefined for shift counts >= 31, so bound every cell at 30
88	__CPROVER_requires(__CPROVER_forall {
89		int _k;
90		(0 <= _k && _k < SIZE * SIZE) ==> ((uint8_t *)board)[_k] <= 30
91	})
92	// drawBoard only reads the board and prints; it writes nothing observable
93	__CPROVER_assigns()
94	// clang-format on
95	{
96		uint8_t x, y, fg, bg;
97		printf("\033[H"); // move cursor to 0,0
98		printf("2048.c %17u pts\n\n", score);
99		for (y = 0; y < SIZE; y++)
100		{
101			for (x = 0; x < SIZE; x++)
102			{
103				// send the addresses of the foreground and background variables,
104				// so that they can be modified by the getColors function
105				getColors(board[x][y], scheme, &fg, &bg);
106				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
107				printf("       ");
108				printf("\033[m"); // reset all modes
109			}
110			printf("\n");
111			for (x = 0; x < SIZE; x++)
112			{
113				getColors(board[x][y], scheme, &fg, &bg);
114				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
115				if (board[x][y] != 0)
116				{
117					uint32_t number = 1 << board[x][y];
118					uint8_t t = 7 - getDigitCount(number);
119					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
120				}
121				else
122				{
123					printf("   ·   ");
124				}
125				printf("\033[m"); // reset all modes
126			}
127			printf("\n");
128			for (x = 0; x < SIZE; x++)
129			{
130				getColors(board[x][y], scheme, &fg, &bg);
131				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
132				printf("       ");
133				printf("\033[m"); // reset all modes
134			}
135			printf("\n");
136		}
137		printf("\n");
138		printf("        ←,↑,→,↓ or q        \n");
139		printf("\033[A"); // one line up
140	}
141	
142	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
143	// clang-format off
144	// the array must be a readable block of SIZE bytes
145	__CPROVER_requires(__CPROVER_is_fresh(array, sizeof(uint8_t[SIZE])))
146	// x is a valid index into the array (it is both read and used as a bound)
147	__CPROVER_requires(x < SIZE)
148	// when x >= 1 the scan runs down toward stop; stop must be reachable from x-1,
149	// otherwise the uint8_t loop counter t underflows below 0 and reads out of bounds
150	__CPROVER_requires(x == 0 || stop < x)
151	// findTarget only reads the array; it never writes anything observable
152	__CPROVER_assigns()
153	// when x is already the first slot the function short-circuits with 0
154	__CPROVER_ensures(x != 0 || __CPROVER_return_value == 0)
155	// the target never lies above the original position ...
156	__CPROVER_ensures(__CPROVER_return_value <= x)
157	// ... and (for x >= 1) never below the stop barrier
158	__CPROVER_ensures(x == 0 || __CPROVER_return_value >= stop)
159	// functional: if every cell in [stop, x) is empty, the target is the stop barrier.
160	// NB: quantifiers reading an is_fresh array must range over a CONSTANT bound
161	// ([0, SIZE)); a symbolic bound makes CBMC read a havoced copy. The real [stop, x)
162	// range is recovered by the inner guard.
163	__CPROVER_ensures(x == 0 ||
164		((__CPROVER_forall { int _z; (0 <= _z && _z < SIZE) ==>
165			((stop <= _z && _z < x) ==> ((const uint8_t *)array)[_z] == 0) })
166			==> __CPROVER_return_value == stop))
167	// functional: otherwise let p be the highest nonzero cell in [stop, x); the target
168	// is p itself when array[p] can merge with array[x], else the slot just above p
169	__CPROVER_ensures(x == 0 ||
170		__CPROVER_forall { int _p; (0 <= _p && _p < SIZE) ==>
171			((stop <= _p && _p < x && ((const uint8_t *)array)[_p] != 0 &&
172			 (__CPROVER_forall { int _q; (0 <= _q && _q < SIZE) ==>
173				((_p < _q && _q < x) ==> ((const uint8_t *)array)[_q] == 0) }))
174			==> __CPROVER_return_value ==
175			    (((const uint8_t *)array)[_p] == ((const uint8_t *)array)[x] ? (uint8_t)_p : (uint8_t)(_p + 1))) })
176	// clang-format on
177	{
178		uint8_t t;
179		// if the position is already on the first, don't evaluate
180		if (x == 0)
181		{
182			return x;
183		}
184		for (t = x - 1;; t--)
185		{
186			if (array[t] != 0)
187			{
188				if (array[t] != array[x])
189				{
190					// merge is not possible, take next position
191					return t + 1;
192				}
193				return t;
194			}
195			else
196			{
197				// we should not slide further, return this one
198				if (t == stop)
199				{
200					return t;
201				}
202			}
203		}
204		// we did not find a target
205		return x;
206	}
207	
208	bool slideArray(uint8_t array[SIZE], uint32_t *score)
209	{
210		bool success = false;
211		uint8_t x, t, stop = 0;
212	
213		for (x = 0; x < SIZE; x++)
214		{
215			if (array[x] != 0)
216			{
217				t = findTarget(array, x, stop);
218				// if target is not original position, then move or merge
219				if (t != x)
220				{
221					// if target is zero, this is a move
222					if (array[t] == 0)
223					{
224						array[t] = array[x];
225					}
226					else if (array[t] == array[x])
227					{
228						// merge (increase power of two)
229						array[t]++;
230						// increase score
231						*score += 1 << array[t];
232						// set stop to avoid double merge
233						stop = t + 1;
234					}
235					array[x] = 0;
236					success = true;
237				}
238			}
239		}
240		return success;
241	}
