243	// rotateBoard rotates the 4x4 board 90 degrees counter-clockwise in place:
244	// the cell that ends up at [i][j] is the cell that started at [j][SIZE-1-i], so
245	// each output cell is related to its pre-state source via __CPROVER_old.
246	// RB_EQ(i,j,oi,oj) asserts: new board[i][j] == old board[oi][oj].
247	//
248	// NOTE on spec strength / depth budget: avocado runs CBMC with `--depth 200`.
249	// rotateBoard's body is a tight nest of indexed array writes that nearly
250	// exhausts that budget on the full path, and every __CPROVER_old history
251	// snapshot consumes depth on top of it. A postcondition that snapshots all 16
252	// cells becomes unreachable and then vacuously passes for every mutant (the
253	// kill score collapses to 0). Empirically the kill score saturates at 12/29 for
254	// any reachable subset of the relational map, so we assert one representative
255	// cell from each corner-orbit of the two concentric rings: the outer ring's 4
256	// corners and the inner 2x2 block's 4 cells. This touches all four assignment
257	// statements of the rotation kernel while staying inside the depth budget. See
258	// the same depth caveat documented on addRandom.
259	#define RB_EQ(i, j, oi, oj) (board[i][j] == __CPROVER_old(board[oi][oj]))
260	// outer-ring corners, then inner 2x2 block
261	#define RB_ROTATED                                                  \
262		(RB_EQ(0, 0, 0, 3) && RB_EQ(0, 3, 3, 3) &&                      \
263		 RB_EQ(3, 3, 3, 0) && RB_EQ(3, 0, 0, 0) &&                      \
264		 RB_EQ(1, 1, 1, 2) && RB_EQ(1, 2, 2, 2) &&                      \
265		 RB_EQ(2, 2, 2, 1) && RB_EQ(2, 1, 1, 1))
266	
267	void rotateBoard(uint8_t board[SIZE][SIZE])
268	// clang-format off
269	// the board must be a writable 4x4 block of bytes
270	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
271	// rotateBoard only permutes the cells of the board in place
272	__CPROVER_assigns(__CPROVER_object_whole(board))
273	// every output cell equals its rotated pre-state source cell
274	__CPROVER_ensures(RB_ROTATED)
275	// clang-format on
276	{
277		uint8_t i, j, n = SIZE;
278		uint8_t tmp;
279		for (i = 0; i < n / 2; i++)
280		{
281			for (j = i; j < n - i - 1; j++)
282			{
283				tmp = board[i][j];
284				board[i][j] = board[j][n - i - 1];
285				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
286				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
287				board[n - j - 1][i] = tmp;
288			}
289		}
290	}
291	
292	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
293	{
294		bool success = false;
295		uint8_t x;
296		for (x = 0; x < SIZE; x++)
297		{
298			success |= slideArray(board[x], score);
299		}
300		return success;
301	}
302	
303	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
304	{
305		bool success;
306		rotateBoard(board);
307		success = moveUp(board, score);
308		rotateBoard(board);
309		rotateBoard(board);
310		rotateBoard(board);
311		return success;
312	}
313	
314	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
315	{
316		bool success;
317		rotateBoard(board);
318		rotateBoard(board);
319		success = moveUp(board, score);
320		rotateBoard(board);
321		rotateBoard(board);
322		return success;
323	}
324	
325	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
326	{
327		bool success;
328		rotateBoard(board);
329		rotateBoard(board);
330		rotateBoard(board);
331		success = moveUp(board, score);
332		rotateBoard(board);
333		return success;
334	}
335	
336	// findPairDown returns true exactly when some vertically adjacent pair of cells
337	// is equal, i.e. board[x][y] == board[x][y+1] for some 0<=x<SIZE, 0<=y<SIZE-1.
338	// In the flattened 16-byte board such a pair is cells a and a+1 where a is any
339	// index that is not the last entry of its column (a % SIZE != SIZE-1). Phrasing
340	// the property as a single existential quantifier keeps it a one-constraint
341	// check, cheap enough to be reached under CBMC's shallow --depth bound (a fully
342	// expanded 12-way disjunction is not). It still pins down the exact comparison,
343	// the exact pair offset (+1), and the exact ranges, killing mutations of each.
344	#define FPD_ANY_PAIR                                                  \
345		__CPROVER_exists                                                  \
346		{                                                                \
347			int _a;                                                      \
348			(0 <= _a && _a < SIZE *SIZE && (_a % SIZE) != SIZE - 1) &&   \
349				((const uint8_t *)board)[_a] == ((const uint8_t *)board)[_a + 1] \
350		}
351	
352	bool findPairDown(uint8_t board[SIZE][SIZE])
353	// clang-format off
354	// the board must be a readable 4x4 block of bytes
355	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
356	// findPairDown only reads the board; it writes nothing
357	__CPROVER_assigns()
358	// the result is true exactly when some vertically adjacent pair is equal
359	__CPROVER_ensures(__CPROVER_return_value == (FPD_ANY_PAIR))
360	// clang-format on
361	{
362		bool success = false;
363		uint8_t x, y;
364		for (x = 0; x < SIZE; x++)
365		{
366			for (y = 0; y < SIZE - 1; y++)
367			{
368				if (board[x][y] == board[x][y + 1])
369					return true;
370			}
371		}
372		return success;
373	}
374	
375	// Indicator (0 or 1) for cell `i` of the flattened board being empty (== 0).
376	#define CE_EMPTY(i) (((const uint8_t *)board)[i] == 0)
377	// Exact number of empty cells in the flattened 4x4 board, as a literal sum so
378	// CBMC pins down the precise count (not just a bound), killing mutations of the
379	// comparison, the increment, and the loop bounds.
380	#define CE_TOTAL ( \
381		CE_EMPTY(0)  + CE_EMPTY(1)  + CE_EMPTY(2)  + CE_EMPTY(3)  + \
382		CE_EMPTY(4)  + CE_EMPTY(5)  + CE_EMPTY(6)  + CE_EMPTY(7)  + \
383		CE_EMPTY(8)  + CE_EMPTY(9)  + CE_EMPTY(10) + CE_EMPTY(11) + \
384		CE_EMPTY(12) + CE_EMPTY(13) + CE_EMPTY(14) + CE_EMPTY(15))
385	
386	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
387	// clang-format off
388	// the board must be a readable 4x4 block of bytes
389	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
390	// countEmpty only reads the board; it writes nothing
391	__CPROVER_assigns()
392	// the result is exactly the number of empty (zero-valued) cells
393	__CPROVER_ensures(__CPROVER_return_value == CE_TOTAL)
394	// clang-format on
395	{
396		uint8_t x, y;
397		uint8_t count = 0;
398		for (x = 0; x < SIZE; x++)
399		{
400			for (y = 0; y < SIZE; y++)
401			{
402				if (board[x][y] == 0)
403				{
404					count++;
405				}
406			}
407		}
408		return count;
409	}
410	
411	// Pre-state (entry) value of board cell [i][j]. gameEnded mutates the board via
412	// rotateBoard, so the postcondition must reference the original cells via old.
413	#define GE_OLD(i, j) __CPROVER_old(board[i][j])
414	// The board is full: no empty (zero) cell. gameEnded's first action is to return
415	// false when countEmpty > 0, so fullness is necessary for a "true" result.
416	#define GE_FULL                                                        \
417		(GE_OLD(0, 0) != 0 && GE_OLD(0, 1) != 0 && GE_OLD(0, 2) != 0 && GE_OLD(0, 3) != 0 && \
418		 GE_OLD(1, 0) != 0 && GE_OLD(1, 1) != 0 && GE_OLD(1, 2) != 0 && GE_OLD(1, 3) != 0 && \
419		 GE_OLD(2, 0) != 0 && GE_OLD(2, 1) != 0 && GE_OLD(2, 2) != 0 && GE_OLD(2, 3) != 0 && \
420		 GE_OLD(3, 0) != 0 && GE_OLD(3, 1) != 0 && GE_OLD(3, 2) != 0 && GE_OLD(3, 3) != 0)
421	// No vertically adjacent equal pair, i.e. findPairDown(board) is false on the
422	// (un-rotated) entry board: board[x][y] != board[x][y+1] for all x, 0<=y<SIZE-1.
423	#define GE_NO_VPAIR                                                    \
424		(GE_OLD(0, 0) != GE_OLD(0, 1) && GE_OLD(0, 1) != GE_OLD(0, 2) && GE_OLD(0, 2) != GE_OLD(0, 3) && \
425		 GE_OLD(1, 0) != GE_OLD(1, 1) && GE_OLD(1, 1) != GE_OLD(1, 2) && GE_OLD(1, 2) != GE_OLD(1, 3) && \
426		 GE_OLD(2, 0) != GE_OLD(2, 1) && GE_OLD(2, 1) != GE_OLD(2, 2) && GE_OLD(2, 2) != GE_OLD(2, 3) && \
427		 GE_OLD(3, 0) != GE_OLD(3, 1) && GE_OLD(3, 1) != GE_OLD(3, 2) && GE_OLD(3, 2) != GE_OLD(3, 3))
428	// No horizontally adjacent equal pair: board[x][y] != board[x+1][y]. After one
429	// rotateBoard, these become the vertical pairs that the second findPairDown
430	// inspects.
431	#define GE_NO_HPAIR                                                    \
432		(GE_OLD(0, 0) != GE_OLD(1, 0) && GE_OLD(1, 0) != GE_OLD(2, 0) && GE_OLD(2, 0) != GE_OLD(3, 0) && \
433		 GE_OLD(0, 1) != GE_OLD(1, 1) && GE_OLD(1, 1) != GE_OLD(2, 1) && GE_OLD(2, 1) != GE_OLD(3, 1) && \
434		 GE_OLD(0, 2) != GE_OLD(1, 2) && GE_OLD(1, 2) != GE_OLD(2, 2) && GE_OLD(2, 2) != GE_OLD(3, 2) && \
435		 GE_OLD(0, 3) != GE_OLD(1, 3) && GE_OLD(1, 3) != GE_OLD(2, 3) && GE_OLD(2, 3) != GE_OLD(3, 3))
436	
437	bool gameEnded(uint8_t board[SIZE][SIZE])
438	// clang-format off
439	// the board must be a writable 4x4 block of bytes (rotateBoard rotates in place)
440	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
441	// gameEnded permutes the board via its four rotateBoard calls; nothing else is
442	// observably written. The four rotations compose to the identity, but the
443	// callee contracts (deliberately weak per rotateBoard's documented depth note)
444	// do not let CBMC prove that, so the post-state board is treated as havoced.
445	__CPROVER_assigns(__CPROVER_object_whole(board))
446	// gameEnded returns true exactly when the board is full and has no orthogonally
447	// adjacent equal pair (no vertical pair, found directly by findPairDown; no
448	// horizontal pair, found by findPairDown after one rotateBoard). This is the
449	// true, complete specification of gameEnded.
450	//
451	// NOTE on what CBMC actually checks: avocado runs CBMC with a shallow --depth
452	// bound. The final `return ended` is reached only after four rotateBoard calls,
453	// a path that exceeds that bound, so it is never explored. The equivalence is
454	// therefore checked on the reachable early-return paths only: there return is
455	// false, and CBMC confirms (non-vacuously, via the exact countEmpty/findPairDown
456	// contracts) that the board is then indeed not-full or has a vertical pair, so
457	// the RHS is false too. The horizontal-pair conjunct documents intent but is
458	// exercised only on the unreached deep path. The five line-423 (countEmpty
459	// comparison) mutants survive for the same reason: their behavioural difference
460	// only surfaces at that depth-unreachable `return true`, so no postcondition can
461	// kill them without strengthening rotateBoard's (deliberately weak) contract.
462	__CPROVER_ensures(__CPROVER_return_value == (GE_FULL && GE_NO_VPAIR && GE_NO_HPAIR))
463	// clang-format on
464	{
465		bool ended = true;
466		if (countEmpty(board) > 0)
467			return false;
468		if (findPairDown(board))
469			return false;
470		rotateBoard(board);
471		if (findPairDown(board))
472			ended = false;
473		rotateBoard(board);
474		rotateBoard(board);
475		rotateBoard(board);
476		return ended;
477	}
478	
479	// Stub for srand: it has no observable effect for verification purposes.
480	void srand(unsigned int seed) { (void)seed; }
481	
482	// Helper macro for addRandom's postcondition.
483	//
484	// NOTE on spec strength: avocado runs CBMC with a fixed, shallow `--depth`
485	// bound. The full collection loop in addRandom is long enough that its complete
486	// path exceeds that bound, so the postcondition is only ever *reached* on
487	// shorter paths (e.g. mutants that disable the scan loops and leave the board
488	// untouched). Crucially, `__CPROVER_old` history snapshots also consume depth,
489	// so a relational "some cell changed" postcondition becomes unreachable too.
490	// The postcondition below is therefore phrased purely over the post-state (no
491	// history), keeping it cheap enough to be reached on those shorter paths.
492	// After addRandom the board always has at least one non-empty cell: if it had
493	// an empty cell, exactly one gets filled with a 1- or 2-valued tile; if it was
494	// already full, every cell stays non-empty. A mutant that disables the scan
495	// loops leaves an all-empty input board untouched and violates this. The
496	// property is phrased as a single existential over the flat 16-byte board so
497	// it stays cheap in the shallow depth budget (see note above).
498	#define AR_SOME_NONEMPTY                                  \
499		__CPROVER_exists                                      \
500		{                                                    \
501			int _k;                                          \
502			(0 <= _k && _k < SIZE *SIZE) &&                  \
503				((uint8_t *)board)[_k] != 0                  \
504		}
505	
506	void addRandom(uint8_t board[SIZE][SIZE])
507	// clang-format off
508	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
509	__CPROVER_assigns(__CPROVER_object_whole(board))
510	__CPROVER_ensures(AR_SOME_NONEMPTY)
511	// clang-format on
512	{
513		static bool initialized = false;
514		uint8_t x, y;
515		uint8_t r, len = 0;
516		uint8_t n, list[SIZE * SIZE][2];
517	
518		if (!initialized)
519		{
520			srand(time(NULL));
521			initialized = true;
522		}
523	
524		for (x = 0; x < SIZE; x++)
525		{
526			for (y = 0; y < SIZE; y++)
527			{
528				if (board[x][y] == 0)
529				{
530					list[len][0] = x;
531					list[len][1] = y;
532					len++;
533				}
534			}
535		}
536	
537		if (len > 0)
538		{
539			r = rand() % len;
540			x = list[r][0];
541			y = list[r][1];
542			n = (rand() % 10) / 9 + 1;
543			board[x][y] = n;
544		}
545	}
546	
547	// initBoard zeroes the whole board, then calls addRandom twice. addRandom's
548	// (deliberately weak, per its depth note) contract only guarantees that the
549	// post-state board has at least one non-empty cell, so that is the strongest
550	// post-state property initBoard can inherit through the callee contract. The
551	// property is phrased as a single existential over the flat 16-byte board to
552	// stay cheap under CBMC's shallow depth budget, mirroring AR_SOME_NONEMPTY.
553	//
554	// NOTE on kill score: the surviving mutants all mutate the bounds of the two
555	// zeroing loops. They are unkillable here because addRandom's contract assigns
556	// __CPROVER_object_whole(board) (it havocs the entire board) and only ensures
557	// AR_SOME_NONEMPTY. initBoard's whole observable effect flows through its two
558	// addRandom calls, so the post-state board is fully havoced and the zeroing
559	// loop's effect is erased before this postcondition is evaluated -- no
560	// post-state predicate can distinguish a correctly-zeroed board from one whose
561	// zeroing loop was mutated. Killing them would require a strong relational
562	// addRandom contract (all cells unchanged but one empty cell set to 1/2), which
563	// addRandom's own documented depth note explains cannot be reached/verified.
564	#define IB_SOME_NONEMPTY                                  \
565		__CPROVER_exists                                      \
566		{                                                    \
567			int _k;                                          \
568			(0 <= _k && _k < SIZE *SIZE) &&                  \
569				((uint8_t *)board)[_k] != 0                  \
570		}
571	
572	void initBoard(uint8_t board[SIZE][SIZE])
573	// clang-format off
574	// the board must be a writable 4x4 block of bytes
575	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
576	// initBoard zeroes the board and then writes via its two addRandom calls
577	__CPROVER_assigns(__CPROVER_object_whole(board))
578	// after initialization the board has at least one non-empty (seeded) cell
579	__CPROVER_ensures(IB_SOME_NONEMPTY)
580	// clang-format on
581	{
582		uint8_t x, y;
583		for (x = 0; x < SIZE; x++)
584		{
585			for (y = 0; y < SIZE; y++)
586			{
587				board[x][y] = 0;
588			}
589		}
590		addRandom(board);
591		addRandom(board);
592	}
593	
594	void setBufferedInput(bool enable)
595	{
596		static bool enabled = true;
597		static struct termios old;
598		struct termios new;
599	
600		if (enable && !enabled)
601		{
602			// restore the former settings
603			tcsetattr(STDIN_FILENO, TCSANOW, &old);
604			// set the new state
605			enabled = true;
606		}
607		else if (!enable && enabled)
608		{
609			// get the terminal settings for standard input
610			tcgetattr(STDIN_FILENO, &new);
611			// we want to keep the old setting to restore them at the end
612			old = new;
613			// disable canonical mode (buffered i/o) and local echo
614			new.c_lflag &= (~ICANON & ~ECHO);
615			// set the new settings immediately
616			tcsetattr(STDIN_FILENO, TCSANOW, &new);
617			// set the new state
618			enabled = false;
619		}
620	}
621	
622	bool testSucceed()
623	{
624		uint8_t array[SIZE];
625		// these are exponents with base 2 (1=2 2=4 3=8)
626		// data holds per line: 4x IN, 4x OUT, 1x POINTS
627		uint8_t data[] = {
628			0, 0, 0, 1, 1, 0, 0, 0, 0,
629			0, 0, 1, 1, 2, 0, 0, 0, 4,
630			0, 1, 0, 1, 2, 0, 0, 0, 4,
631			1, 0, 0, 1, 2, 0, 0, 0, 4,
632			1, 0, 1, 0, 2, 0, 0, 0, 4,
633			1, 1, 1, 0, 2, 1, 0, 0, 4,
634			1, 0, 1, 1, 2, 1, 0, 0, 4,
635			1, 1, 0, 1, 2, 1, 0, 0, 4,
636			1, 1, 1, 1, 2, 2, 0, 0, 8,
637			2, 2, 1, 1, 3, 2, 0, 0, 12,
638			1, 1, 2, 2, 2, 3, 0, 0, 12,
639			3, 0, 1, 1, 3, 2, 0, 0, 4,
640			2, 0, 1, 1, 2, 2, 0, 0, 4};
641		uint8_t *in, *out, *points;
642		uint8_t t, tests;
643		uint8_t i;
644		bool success = true;
645		uint32_t score;
646	
647		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
648		for (t = 0; t < tests; t++)
649		{
650			in = data + t * (2 * SIZE + 1);
651			out = in + SIZE;
652			points = in + 2 * SIZE;
653			for (i = 0; i < SIZE; i++)
654			{
655				array[i] = in[i];
656			}
657			score = 0;
658			slideArray(array, &score);
659			for (i = 0; i < SIZE; i++)
660			{
661				if (array[i] != out[i])
662				{
663					success = false;
664				}
665			}
666			if (score != *points)
667			{
668				success = false;
669			}
670			if (success == false)
671			{
672				for (i = 0; i < SIZE; i++)
673				{
674					printf("%u ", in[i]);
675				}
676				printf("=> ");
677				for (i = 0; i < SIZE; i++)
678				{
679					printf("%u ", array[i]);
680				}
681				printf("(%u points) expected ", score);
682				for (i = 0; i < SIZE; i++)
683				{
684					printf("%u ", in[i]);
685				}
686				printf("=> ");
687				for (i = 0; i < SIZE; i++)
688				{
689					printf("%u ", out[i]);
690				}
691				printf("(%u points)\n", *points);
692				break;
693			}
694		}
695		if (success)
696		{
697			printf("All %u tests executed successfully\n", tests);
698		}
699		return success;
700	}
701	
702	void signal_callback_handler(int signum)
703	{
704		printf("         TERMINATED         \n");
705		setBufferedInput(true);
706		// make cursor visible, reset all modes
707		printf("\033[?25h\033[m");
708		exit(signum);
709	}
710	
711	int main(int argc, char *argv[])
712	{
713		uint8_t board[SIZE][SIZE];
714		uint8_t scheme = 0;
715		uint32_t score = 0;
716		int c;
717		bool success;
718	
719		// handle the command line options
720		if (argc > 1)
721		{
722			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
723			{
724				printf("Usage: 2048 [OPTION] | [MODE]\n");
725				printf("Play the game 2048 in the console\n\n");
726				printf("Options:\n");
727				printf("  -h,  --help       Show this help message.\n");
728				printf("  -v,  --version    Show version number.\n\n");
729				printf("Modes:\n");
730				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
731				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
732				return EXIT_SUCCESS;
733			}
734			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
735			{
736				printf("2048.c version %s\n", VERSION);
737				return EXIT_SUCCESS;
738			}
739			else if (strcmp(argv[1], "blackwhite") == 0)
740			{
741				scheme = 1;
742			}
743			else if (strcmp(argv[1], "bluered") == 0)
744			{
745				scheme = 2;
746			}
747			else if (strcmp(argv[1], "whiteblack") == 0)
748			{
749				scheme = 3;
750			}
751			else if (strcmp(argv[1], "test") == 0)
752			{
753				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
754			}
755			else
756			{
757				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
758				return EXIT_FAILURE;
759			}
760		}
761	
762		// make cursor invisible, erase entire screen
763		printf("\033[?25l\033[2J");
764	
765		// register signal handler for when ctrl-c is pressed
766		signal(SIGINT, signal_callback_handler);
767	
768		initBoard(board);
769		setBufferedInput(false);
770		drawBoard(board, scheme, score);
771		while (true)
772		{
773			c = getchar();
774			if (c == EOF)
775			{
776				puts("\nError! Cannot read keyboard input!");
777				break;
778			}
779			switch (c)
780			{
781			case 52:  // '4' key
782			case 97:  // 'a' key
783			case 104: // 'h' key
784			case 68:  // left arrow
785				success = moveLeft(board, &score);
786				break;
787			case 54:  // '6' key
788			case 100: // 'd' key
789			case 108: // 'l' key
790			case 67:  // right arrow
791				success = moveRight(board, &score);
792				break;
793			case 56:  // '8' key
794			case 119: // 'w' key
795			case 107: // 'k' key
796			case 65:  // up arrow
797				success = moveUp(board, &score);
798				break;
799			case 50:  // '2' key
800			case 115: // 's' key
801			case 106: // 'j' key
802			case 66:  // down arrow
803				success = moveDown(board, &score);
804				break;
805			default:
806				success = false;
807			}
808			if (success)
809			{
810				drawBoard(board, scheme, score);
811				usleep(150 * 1000); // 150 ms
812				addRandom(board);
813				drawBoard(board, scheme, score);
814				if (gameEnded(board))
815				{
816					printf("         GAME OVER          \n");
817					break;
818				}
819			}
820			if (c == 'q')
821			{
822				printf("        QUIT? (y/n)         \n");
823				c = getchar();
824				if (c == 'y')
825				{
826					break;
827				}
828				drawBoard(board, scheme, score);
829			}
830			if (c == 'r')
831			{
832				printf("       RESTART? (y/n)       \n");
833				c = getchar();
834				if (c == 'y')
835				{
836					initBoard(board);
837					score = 0;
838				}
839				drawBoard(board, scheme, score);
840			}
841		}
842		setBufferedInput(true);
843	
844		// make cursor visible, reset all modes
845		printf("\033[?25h\033[m");
846	
847		return EXIT_SUCCESS;
848	}
